var months=[];
var monthly=[];
var cumulative=[];
var movingTotal=[];
var cum=0;
var mt=rawData.prev_year_total;
var prevMonthly=[100,105,110,108,115,120,118,125,130,128,135,126];
rawData.rows.forEach(function(r,i){
  months.push(r.m);
  monthly.push(r.v);
  cum+=r.v;
  cumulative.push(cum);
  mt=mt-prevMonthly[i]+r.v;
  movingTotal.push(mt);
});
transformedData={months:months,monthly:monthly,cumulative:cumulative,movingTotal:movingTotal};
